package org.mage.test.cards.copy;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

public class EstridsInvocationReproTest extends CardTestPlayerBase {

    @Test
    public void canUseAuraUpkeepBlinkTwice() {
        addCard(Zone.HAND, playerA, "Inferno Fist", 1);
        addCard(Zone.HAND, playerA, "Estrid's Invocation", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Mountain", 2);
        addCard(Zone.BATTLEFIELD, playerA, "Island", 3);
        addCard(Zone.BATTLEFIELD, playerA, "Silvercoat Lion", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Pillarfield Ox", 1);

        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Inferno Fist", "Silvercoat Lion");
        waitStackResolved(1, PhaseStep.PRECOMBAT_MAIN);
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // copy on initial ETB
        setChoice(playerA, "Inferno Fist");
        setChoice(playerA, "Pillarfield Ox"); // Aura attachment for copy

        setChoice(playerA, true); // turn 3 upkeep: exile and return
        setChoice(playerA, true); // copy on return
        setChoice(playerA, "Inferno Fist");
        setChoice(playerA, "Pillarfield Ox");

        setChoice(playerA, true); // turn 5 upkeep: exile and return again
        setChoice(playerA, true); // copy on return again
        setChoice(playerA, "Inferno Fist");
        setChoice(playerA, "Pillarfield Ox");

        setStrictChooseMode(true);
        setStopAt(5, PhaseStep.PRECOMBAT_MAIN);
        execute();

        assertPermanentCount(playerA, "Inferno Fist", 2);
        assertPowerToughness(playerA, "Silvercoat Lion", 4, 2);
        assertPowerToughness(playerA, "Pillarfield Ox", 4, 4);
        assertGraveyardCount(playerA, "Estrid's Invocation", 0);
        assertExileCount(playerA, "Estrid's Invocation", 0);
    }
}

