}

class EstridsInvocationEffect extends OneShotEffect {

    EstridsInvocationEffect() {
        super(Outcome.Neutral);
        this.staticText = "exile this enchantment. If you do, return it to the battlefield under its owner's control";
    }

    private EstridsInvocationEffect(final EstridsInvocationEffect effect) {
        super(effect);
    }

    @Override
    public EstridsInvocationEffect copy() {
        return new EstridsInvocationEffect(this);
    }

    @Override
    public boolean apply(Game game, Ability source) {
        Player player = game.getPlayer(source.getControllerId());
        Permanent permanent = source.getSourcePermanentIfItStillExists(game);
        if (permanent == null || player == null) {
            return false;
        }
        Card card = permanent.getMainCard();
        if (card == null || !player.moveCards(permanent, Zone.EXILED, source, game)) {
            return false;
        }
        resetPrintedCharacteristics(card, game);
        return player.moveCards(card, Zone.BATTLEFIELD, source, game, false, false, true, null);
    }

    private static void resetPrintedCharacteristics(Card card, Game game) {
        card.getColor(game).setColor(card.getColor());
        card.removeAllCardTypes(game);
        for (CardType cardType : card.getCardType()) {
            card.addCardType(game, cardType);
        }
        card.removeAllSubTypes(game);
        for (SubType subType : card.getSubtype()) {
            card.addSubType(game, subType);
        }
        card.removeAllSuperTypes(game);
        for (SuperType superType : card.getSuperType()) {
            card.addSuperType(game, superType);
        }
    }
}

